import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"奠基身法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/奠基身法.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/奠基身法.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/武学基础/奠基身法.md"};function l(p,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"奠基身法",tabindex:"-1"},[s("奠基身法 "),e("a",{class:"header-anchor",href:"#奠基身法","aria-label":'Permalink to "奠基身法"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风020")])])],-1),o('<h1 id="奠基身法-1" tabindex="-1">奠基身法 <a class="header-anchor" href="#奠基身法-1" aria-label="Permalink to &quot;奠基身法&quot;">​</a></h1><p>奠基身法<br> D+500<br> 前置：武学基础-身法入门<br> 所谓身法，便是方寸挪移之法，与步法唯速迥异，身法以变为妙，讲究生死一步隔，故更为险要，此法奠基乃好斗者之重，唯重练此法，方能先制克敌、出奇制胜。</p><p>兑换后可以修心身法精要，将开始：<br> *身法修行：每当修习者经历一个影片，其对身法的熟练便更进一步，愈发难以捉摸的行动轨迹将为其提供两点的先攻加值。</p><p>此外，修习者在经历三场影片的修行后，将习得一种基础的挪移之法，即：<br> *方寸步：这是一种类招架能力，使用时将额外消耗一点内力，然后进行一次纯运动技能检定，本次检定无法获得任何其他能力带来的额外加值。<br> 使用者会在招架的基础上额外减免等同于成功数的伤害，表现上视为修行者在瞬息间闪出原本的方位，籍以此来减少收到的伤害。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
